import{_ as a,o as t,c as r,ag as i}from"./chunks/framework.DXGyWiRo.js";const l="/images/navi14.png?raw=true",b=JSON.parse('{"title":"14 扩展Web框架","description":"","frontmatter":{},"headers":[],"relativePath":"14/0.md","filePath":"14/0.md","lastUpdated":null}'),o={name:"14/0.md"};function s(n,e,_,p,d,h){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="_14-扩展web框架" tabindex="-1">14 扩展Web框架 <a class="header-anchor" href="#_14-扩展web框架" aria-label="Permalink to &quot;14 扩展Web框架&quot;">​</a></h1><p>第十三章介绍了如何开发一个Web框架，通过介绍MVC、路由、日志处理、配置处理完成了一个基本的框架系统，但是一个好的框架需要一些方便的辅助工具来快速的开发Web，那么我们这一章将就如何提供一些快速开发Web的工具进行介绍，第一小节介绍如何处理静态文件，如何利用现有的twitter开源的bootstrap进行快速的开发美观的站点，第二小节介绍如何利用前面介绍的session来进行用户登录处理，第三小节介绍如何方便的输出表单、这些表单如何进行数据验证，如何快速的结合model进行数据的增删改操作，第四小节介绍如何进行一些用户认证，包括http basic认证、http digest认证，第五小节介绍如何利用前面介绍的i18n支持多语言的应用开发。第六小节介绍了如何集成Go的pprof包用于性能调试。</p><p>通过本章的扩展，beego框架将具有快速开发Web的特性，最后我们将讲解如何利用这些扩展的特性扩展开发第十三章开发的博客系统，通过开发一个完整、美观的博客系统让读者了解beego开发带给你的快速。</p><h2 id="目录" tabindex="-1">目录 <a class="header-anchor" href="#目录" aria-label="Permalink to &quot;目录&quot;">​</a></h2><p><img src="'+l+'" alt=""></p><h2 id="links" tabindex="-1">links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;links&quot;">​</a></h2><ul><li><a href="/">目录</a></li><li>上一章: <a href="/13/6.html">第十三章总结</a></li><li>下一节: <a href="/14/1.html">静态文件支持</a></li></ul>',7)])])}const m=a(o,[["render",s]]);export{b as __pageData,m as default};
